<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
        }

        body {
            overflow: hidden;
            height: 100vh;
            width: 100vw;
            background-color: #2e3440;
            color: #d8dee9;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: rgba(31, 35, 42, 0.9);
            backdrop-filter: blur(10px);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 1000;
            border-top: 1px solid #4c566a;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin: 0 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            border-radius: 8px;
            transition: background-color 0.2s;
        }

        .launcher:hover {
            background-color: rgba(76, 143, 165, 0.2);
        }

        .launcher-icon {
            width: 32px;
            height: 32px;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 20px;
        }

        #open-files .launcher-icon { background-color: #4c566a; }
        #open-notepad .launcher-icon { background-color: #8fbcbb; }

        /* Windows */
        .window {
            position: absolute;
            width: 600px;
            height: 400px;
            min-width: 360px;
            min-height: 240px;
            background-color: rgba(46, 52, 64, 0.95);
            border-radius: 12px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            z-index: 100;
            transition: transform 0.2s ease-in-out;
        }

        .window-header {
            height: 36px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 12px;
            cursor: default;
            user-select: none;
        }

        .window-title {
            font-size: 14px;
            color: #d8dee9;
        }

        .window-controls {
            display: flex;
            gap: 6px;
        }

        .win-close, .win-minimize, .win-maximize {
            width: 20px;
            height: 20px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            font-size: 14px;
        }

        .win-close { background-color: #bf616a; color: white; }
        .win-minimize { background-color: #ebcb8b; color: black; }
        .win-maximize { background-color: #a3be8c; color: black; }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 16px;
            position: relative;
        }

        /* Files App */
        #files-window {
            top: 50px;
            left: 50%;
            transform: translateX(-50%);
        }

        .files-path {
            background-color: rgba(255, 255, 255, 0.1);
            padding: 8px 16px;
            border-radius: 8px;
            margin-bottom: 16px;
            font-family: monospace;
            display: flex;
            align-items: center;
        }

        .files-path span {
            color: #88c0d0;
            cursor: pointer;
        }

        .fs-item {
            padding: 12px 16px;
            margin-bottom: 8px;
            background-color: rgba(255, 255, 255, 0.05);
            border-radius: 8px;
            cursor: pointer;
            display: flex;
            align-items: center;
            transition: background-color 0.2s;
        }

        .fs-item:hover {
            background-color: rgba(255, 255, 255, 0.1);
        }

        .fs-item.folder {
            color: #88c0d0;
        }

        .fs-item.file {
            color: #d8dee9;
        }

        .fs-icon {
            margin-right: 12px;
            font-size: 24px;
        }

        /* Notepad App */
        #notepad-window {
            top: 50px;
            left: calc(50% + 300px);
            transform: translateX(-50%);
        }

        .tabs-container {
            background-color: #4c566a;
            display: flex;
            align-items: center;
            padding-left: 8px;
        }

        #tabs {
            display: flex;
            overflow-x: auto;
            width: calc(100% - 32px);
        }

        .tab {
            padding: 8px 16px;
            background-color: rgba(0, 0, 0, 0.1);
            border-radius: 8px 8px 0 0;
            margin-right: 4px;
            cursor: pointer;
            white-space: nowrap;
            min-width: 80px;
            text-align: center;
        }

        .tab.active {
            background-color: #434c5e;
            color: #d8dee9;
            font-weight: bold;
        }

        .new-tab-btn {
            padding: 8px 12px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            background-color: rgba(0, 0, 0, 0.1);
            border-radius: 8px;
        }

        #editor {
            width: 100%;
            height: calc(100% - 36px);
            background-color: #2e3440;
            color: #d8dee9;
            border: none;
            padding: 16px;
            font-family: monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        /* Dragging */
        .dragging {
            cursor: move;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div id="open-files" class="launcher">
                <div class="launcher-icon">📁</div>
            </div>
            <div id="open-notepad" class="launcher">
                <div class="launcher-icon">📝</div>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window" style="display: none;">
            <div class="window-header">
                <div class="window-title">Files</div>
                <div class="window-controls">
                    <div class="win-close">×</div>
                </div>
            </div>
            <div class="window-content">
                <div class="files-path" id="files-path">
                    /
                </div>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="display: none;">
            <div class="window-header">
                <div class="window-title">Notepad</div>
                <div class="window-controls">
                    <div class="win-close">×</div>
                </div>
            </div>
            <div class="window-content">
                <div class="tabs-container">
                    <div id="tabs"></div>
                    <div id="new-tab" class="new-tab-btn">+</div>
                </div>
                <textarea id="editor"></textarea>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            "bin": { type: "folder", children: {} },
            "etc": { type: "folder", children: {} },
            "home": { 
                type: "folder", 
                children: {
                    "user": {
                        type: "folder",
                        children: {
                            "Documents": { type: "folder", children: {} },
                            "Downloads": { type: "folder", children: {} },
                            "Pictures": { type: "folder", children: {} }
                        }
                    }
                }
            },
            "usr": { 
                type: "folder", 
                children: {
                    "bin": { type: "folder", children: {} },
                    "lib": { type: "folder", children: {} }
                }
            },
            "var": { 
                type: "folder", 
                children: {
                    "log": { type: "folder", children: {} },
                    "www": { type: "folder", children: {} }
                }
            }
        };

        // Files app state
        let currentPath = [];

        // Notepad state
        let tabs = [];
        let activeTabId = null;
        let tabCounter = 0;

        // DOM Elements
        const desktop = document.getElementById('desktop');
        const taskbar = document.getElementById('taskbar');
        const openFilesBtn = document.getElementById('open-files');
        const openNotepadBtn = document.getElementById('open-notepad');
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');
        const filesPath = document.getElementById('files-path');
        const filesList = document.getElementById('files-list');
        const tabsContainer = document.getElementById('tabs');
        const newTabBtn = document.getElementById('new-tab');
        const editor = document.getElementById('editor');

        // Files App Functions
        function updateFilesPath() {
            if (currentPath.length === 0) {
                filesPath.textContent = '/';
            } else {
                filesPath.innerHTML = '/' + currentPath.join('/');
            }
        }

        function renderFileList() {
            filesList.innerHTML = '';

            // Add up button if not at root
            if (currentPath.length > 0) {
                const upItem = document.createElement('div');
                upItem.className = 'fs-item folder';
                upItem.id = 'files-up';
                upItem.innerHTML = '<span class="fs-icon">⬆️</span><span>.. (Parent Directory)</span>';

                upItem.addEventListener('click', function(e) {
                    e.stopPropagation();
                    if (currentPath.length > 0) {
                        currentPath.pop();
                        updateFilesPath();
                        renderFileList();
                    }
                });

                filesList.appendChild(upItem);
            }

            // Get current directory
            let dir = fileSystem;
            for (const segment of currentPath) {
                if (dir.children && dir.children[segment]) {
                    dir = dir.children[segment];
                } else {
                    break;
                }
            }

            // Render folders first, then files
            const items = [];

            if (dir.type === 'folder' && dir.children) {
                Object.keys(dir.children).forEach(name => {
                    const item = dir.children[name];
                    items.push({
                        name: name,
                        type: item.type,
                        isFolder: item.type === 'folder'
                    });
                });

                // Sort folders first, then alphabetically
                items.sort((a, b) => {
                    if (a.isFolder && !b.isFolder) return -1;
                    if (!a.isFolder && b.isFolder) return 1;
                    return a.name.localeCompare(b.name);
                });

                items.forEach(item => {
                    const itemDiv = document.createElement('div');
                    itemDiv.className = `fs-item ${item.type}`;
                    itemDiv.innerHTML = `<span class="fs-icon">${item.isFolder ? '📁' : '📄'}</span><span>${item.name}</span>`;

                    if (item.isFolder) {
                        itemDiv.addEventListener('click', function(e) {
                            e.stopPropagation();
                            currentPath.push(item.name);
                            updateFilesPath();
                            renderFileList();
                        });
                    } else {
                        itemDiv.addEventListener('dblclick', function(e) {
                            e.stopPropagation();
                            alert(`Opening file: ${item.name}`);
                        });
                    }

                    filesList.appendChild(itemDiv);
                });
            }
        }

        // Notepad Functions
        function createTab(title = 'Untitled') {
            const tabId = `tab-${++tabCounter}`;
            tabs.push({
                id: tabId,
                title: title,
                content: ''
            });

            renderTabs();
            activateTab(tabId);
            saveTabsToStorage();
        }

        function renderTabs() {
            tabsContainer.innerHTML = '';

            tabs.forEach((tab, index) => {
                const tabElement = document.createElement('div');
                tabElement.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabElement.textContent = tab.title;

                // Click to activate
                tabElement.addEventListener('click', function(e) {
                    e.stopPropagation();
                    activateTab(tab.id);
                });

                tabsContainer.appendChild(tabElement);
            });
        }

        function activateTab(tabId) {
            activeTabId = tabId;

            // Update UI
            renderTabs();

            // Set editor content
            const tab = tabs.find(t => t.id === tabId);
            if (tab) {
                editor.value = tab.content || '';
            }

            saveTabsToStorage();
        }

        function updateActiveTabContent() {
            if (activeTabId) {
                const tab = tabs.find(t => t.id === activeTabId);
                if (tab) {
                    tab.content = editor.value;
                    saveTabsToStorage();
                }
            }
        }

        function saveTabsToStorage() {
            localStorage.setItem('ubuntu-notepad-tabs', JSON.stringify(tabs));
            localStorage.setItem('ubuntu-notepad-active-tab', activeTabId);
        }

        function loadTabsFromStorage() {
            const savedTabs = localStorage.getItem('ubuntu-notepad-tabs');
            if (savedTabs) {
                tabs = JSON.parse(savedTabs);

                // Restore active tab
                const savedActiveTab = localStorage.getItem('ubuntu-notepad-active-tab');
                if (savedActiveTab && tabs.some(t => t.id === savedActiveTab)) {
                    activeTabId = savedActiveTab;
                } else if (tabs.length > 0) {
                    activeTabId = tabs[0].id;
                }

                // Update tab counter
                const maxId = Math.max(...tabs.map(t => parseInt(t.id.split('-')[1]) || 0));
                tabCounter = maxId;
            } else {
                createTab();
            }

            renderTabs();
            if (activeTabId) {
                activateTab(activeTabId);
            }
        }

        // Window Management
        function toggleWindow(windowId, btnId) {
            const windowElement = document.getElementById(windowId);
            const isHidden = windowElement.style.display === 'none' || !windowElement.style.display;

            if (isHidden) {
                windowElement.style.display = 'flex';

                // Bring to front
                const allWindows = document.querySelectorAll('.window');
                let maxZIndex = 100;
                allWindows.forEach(win => {
                    const zIndex = parseInt(window.getComputedStyle(win).zIndex);
                    if (!isNaN(zIndex) && zIndex > maxZIndex) {
                        maxZIndex = zIndex;
                    }
                });
                windowElement.style.zIndex = maxZIndex + 1;

                // Center the window on screen
                centerWindow(windowElement);
            } else {
                windowElement.style.display = 'none';
            }
        }

        function centerWindow(windowElement) {
            const desktopRect = desktop.getBoundingClientRect();
            const winWidth = parseInt(window.getComputedStyle(windowElement).width);
            const winHeight = parseInt(window.getComputedStyle(windowElement).height);

            // Calculate position to center on screen
            const left = (desktopRect.width - winWidth) / 2;
            const top = (desktopRect.height - winHeight) / 3; // Slightly higher

            windowElement.style.left = `${left}px`;
            windowElement.style.top = `${top}px`;
        }

        // Drag functionality for windows
        let isDragging = false;
        let dragOffsetX = 0;
        let dragOffsetY = 0;
        let draggedWindow = null;

        document.addEventListener('mousedown', function(e) {
            const header = e.target.closest('.window-header');
            if (header) {
                const windowElement = header.closest('.window');
                if (windowElement) {
                    isDragging = true;
                    draggedWindow = windowElement;

                    // Bring to front
                    const allWindows = document.querySelectorAll('.window');
                    let maxZIndex = 100;
                    allWindows.forEach(win => {
                        const zIndex = parseInt(window.getComputedStyle(win).zIndex);
                        if (!isNaN(zIndex) && zIndex > maxZIndex) {
                            maxZIndex = zIndex;
                        }
                    });
                    windowElement.style.zIndex = maxZIndex + 1;

                    // Calculate offset
                    const rect = windowElement.getBoundingClientRect();
                    dragOffsetX = e.clientX - rect.left;
                    dragOffsetY = e.clientY - rect.top;
                }
            }
        });

        document.addEventListener('mousemove', function(e) {
            if (isDragging && draggedWindow) {
                e.preventDefault();

                // Calculate new position
                let newX = e.clientX - dragOffsetX;
                let newY = e.clientY - dragOffsetY;

                // Keep within desktop bounds
                const desktopRect = desktop.getBoundingClientRect();
                const winWidth = parseInt(window.getComputedStyle(draggedWindow).width);
                const winHeight = parseInt(window.getComputedStyle(draggedWindow).height);

                newX = Math.max(0, Math.min(newX, desktopRect.width - winWidth));
                newY = Math.max(0, Math.min(newY, desktopRect.height - winHeight));

                draggedWindow.style.left = `${newX}px`;
                draggedWindow.style.top = `${newY}px`;
            }
        });

        document.addEventListener('mouseup', function() {
            isDragging = false;
            draggedWindow = null;
        });

        // Event Listeners
        openFilesBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            toggleWindow('files-window');

            // Initialize files app if not already done
            if (currentPath.length === 0) {
                updateFilesPath();
                renderFileList();
            }
        });

        openNotepadBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            toggleWindow('notepad-window');

            // Load tabs if not already loaded
            if (tabs.length === 0) {
                loadTabsFromStorage();
            }
        });

        document.querySelectorAll('.win-close').forEach(closeBtn => {
            closeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                const windowElement = this.closest('.window');
                windowElement.style.display = 'none';
            });
        });

        // Files app controls
        filesPath.addEventListener('click', function(e) {
            if (e.target.tagName === 'SPAN') {
                // Reset to root and navigate to clicked path segment
                currentPath = [];
                const pathSegments = e.target.textContent.split('/').filter(s => s);

                for (let i = 0; i < pathSegments.length; i++) {
                    currentPath.push(pathSegments[i]);
                }

                updateFilesPath();
                renderFileList();
            }
        });

        // Notepad controls
        newTabBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            createTab(`Untitled-${tabs.length + 1}`);
        });

        editor.addEventListener('input', updateActiveTabContent);

        // Initialize on load
        window.addEventListener('load', function() {
            // Center windows initially
            centerWindow(filesWindow);
            centerWindow(notepadWindow);

            // Load notepad tabs from storage
            loadTabsFromStorage();
        });

        // Prevent default drag behavior for images and other elements
        document.addEventListener('dragstart', function(e) {
            e.preventDefault();
        });
    </script>
</body>
</html>
